import { setup, assign, fromPromise } from 'xstate';

type Profile = { name: string; email: string };

export const profileEditMachine = setup({
  types: {
    context: {} as {
      current: Profile;
      draft: Profile;
      dirty: Set<keyof Profile>;
      error: string | null;
    },
    events: {} as
      | { type: 'EDIT' }
      | { type: 'CHANGE_NAME'; value: string }
      | { type: 'CHANGE_EMAIL'; value: string }
      | { type: 'SAVE' }
      | { type: 'CANCEL' }
      | { type: 'ACK' },
  },
  actors: {
    save: fromPromise<Profile, Profile>(async ({ input }) => input),
  },
}).createMachine({
  id: 'profileEdit',
  initial: 'viewing',
  context: {
    current: { name: '', email: '' },
    draft: { name: '', email: '' },
    dirty: new Set<keyof Profile>(),
    error: null,
  },
  states: {
    viewing: {
      on: { EDIT: { target: 'editing' } },
    },
    editing: {
      on: {
        CHANGE_NAME: {
          actions: assign({
            draft: ({ context, event }) => ({ ...context.draft, name: event.value }),
            dirty: ({ context }) => new Set(context.dirty).add('name'),
          }),
        },
        CHANGE_EMAIL: {
          actions: assign({
            draft: ({ context, event }) => ({ ...context.draft, email: event.value }),
            dirty: ({ context }) => new Set(context.dirty).add('email'),
          }),
        },
        SAVE: { target: 'saving' },
        CANCEL: {
          target: 'viewing',
          actions: assign({
            draft: ({ context }) => context.current,
            dirty: () => new Set<keyof Profile>(),
          }),
        },
      },
    },
    saving: {
      invoke: {
        src: 'save',
        input: ({ context }) => context.draft,
        onDone: {
          target: 'saved',
          actions: assign({
            current: ({ event }) => event.output,
            dirty: () => new Set<keyof Profile>(),
            error: () => null,
          }),
        },
        onError: {
          target: 'error',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    saved: { on: { ACK: 'viewing' } },
    error: { on: { ACK: 'editing' } },
  },
});
```

Keep a `Set<keyof Profile>` on context and update it inside each change action. The UI reads `state.context.dirty.has('name')`.

