import { setup, assign } from 'xstate';

export const accountDeletionMachine = setup({
  types: {
    context: {} as { userId: string; requestedAt: number | null },
    events: {} as
      | { type: 'REQUEST_DELETE' }
      | { type: 'CONFIRM' }
      | { type: 'CANCEL' }
      | { type: 'UNDO' },
  },
  delays: {
    GRACE: 30 * 24 * 60 * 60 * 1000,
  },
}).createMachine({
  id: 'accountDeletion',
  initial: 'idle',
  context: { userId: '', requestedAt: null },
  states: {
    idle: { on: { REQUEST_DELETE: 'confirming' } },
    confirming: {
      on: {
        CONFIRM: {
          target: 'gracePeriod',
          actions: assign({ requestedAt: () => Date.now() }),
        },
        CANCEL: 'idle',
      },
    },
    gracePeriod: {
      after: { GRACE: 'deleted' },
      on: {
        UNDO: {
          target: 'idle',
          actions: assign({ requestedAt: () => null }),
        },
      },
    },
    deleted: { type: 'final' },
  },
});
```

Declare the delay in `setup.delays` as a function of context. The state then references it by name in `after`.

