import { setup, assign } from 'xstate';

export const undoableDeleteMachine = setup({
  types: {
    context: {} as { graceMs: number },
    events: {} as { type: 'UNDO' },
  },
  delays: {
    GRACE: ({ context }) => context.graceMs,
  },
}).createMachine({
  id: 'undoableDelete',
  initial: 'pendingDelete',
  context: { graceMs: 7 * 24 * 60 * 60 * 1000 },
  states: {
    pendingDelete: {
      after: { GRACE: 'deleted' },
      on: {
        UNDO: {
          target: 'active',
          actions: assign({ graceMs: ({ context }) => context.graceMs }),
        },
      },
    },
    active: {},
    deleted: { type: 'final' },
  },
});
```

When a state has `after: { DELAY: target }`, XState schedules an internal delayed event and clears it automatically when the state is exited. So transitioning out on `UNDO` cancels the deletion without needing an explicit `cancel(...)` call.

