import { setup, assign } from 'xstate';

export const branchingSurveyMachine = setup({
  types: {
    context: {} as { likesCats: boolean | null },
    events: {} as { type: 'ANSWER'; value: boolean },
  },
  guards: {
    saidYes: ({ context }) => context.likesCats === true,
  },
}).createMachine({
  id: 'branchingSurvey',
  initial: 'ask',
  context: { likesCats: null },
  states: {
    ask: {
      on: {
        ANSWER: [
          {
            actions: assign({ likesCats: ({ event }) => event.value }),
            target: 'recordAnswer',
          },
        ],
      },
    },
    recordAnswer: {
      always: [
        { guard: 'saidYes', target: 'catFollowUp' },
        { target: 'dogFollowUp' },
      ],
    },
    catFollowUp: { type: 'final' },
    dogFollowUp: { type: 'final' },
  },
});
```

An `always` (eventless) transition runs on state entry and re-evaluates when context changes. That lets a survey land in a neutral `recordAnswer` state and immediately route to the right follow-up based on what was stored.

