import { setup, assign } from 'xstate';

type Question = { id: number; correct: string };

export const quizMachine = setup({
  types: {
    context: {} as {
      questions: Question[];
      index: number;
      score: number;
    },
    events: {} as { type: 'ANSWER'; value: string },
  },
  delays: { PER_Q: 10_000 },
  guards: {
    hasMore: ({ context }) => context.index < context.questions.length - 1,
  },
}).createMachine({
  id: 'quiz',
  initial: 'asking',
  context: {
    questions: [
      { id: 1, correct: 'a' },
      { id: 2, correct: 'b' },
      { id: 3, correct: 'c' },
    ],
    index: 0,
    score: 0,
  },
  states: {
    asking: {
      after: { PER_Q: { target: 'scoring' } },
      on: { ANSWER: { target: 'scoring' } },
    },
    scoring: {
      entry: assign({
        score: ({ context, event }) => {
          if (event.type !== 'ANSWER') return context.score;
          const q = context.questions[context.index];
          return event.value === q.correct ? context.score + 1 : context.score;
        },
      }),
      always: [
        {
          guard: 'hasMore',
          target: 'asking',
          actions: assign({ index: ({ context }) => context.index + 1 }),
        },
        { target: 'done' },
      ],
    },
    done: { type: 'final' },
  },
});
```

Put the timer on the question state via `after`. When the state exits on ANSWER, XState cancels the pending delayed event automatically, so no explicit `cancel` call is needed.

